/**
 * Build a full NotificationPayload from input and dispatch to the appropriate adapter.
 * Notifications for the same recipient are serialized to guarantee delivery order.
 */
async dispatchNotification(
  input: CreateNotificationInput,
): Promise<NotificationResult> {
  const key = input.recipient;
  let resultForCaller: NotificationResult;

  const previous = this.dispatchQueues.get(key) ?? Promise.resolve();
  const current = previous.then(async () => {
    resultForCaller = await this.executeDispatch(input);
  });
  this.dispatchQueues.set(key, current);

  await current;
  return resultForCaller!;
}

/**
 * Internal: perform the actual dispatch (preference check, adapter send, logging).
 */
private async executeDispatch(
  input: CreateNotificationInput,
): Promise<NotificationResult> {
  // Check user preferences before sending
  if (input.userId && this.preferencesService) {
    if (!this.preferencesService.shouldNotify(input.userId, input.type, input.channel)) {
      this.logger.info(
        `Notification suppressed for user ${input.userId}: ${input.type} via ${input.channel} (user preference)`,
      );
      const result: NotificationResult = {
        notificationId: generateNotificationId(),
        channel: input.channel,
        success: false,
        error: 'Notification suppressed by user preferences',
        deliveredAt: new Date(),
      };
      this.results.push(result);
      this.historyService?.logNotification(input, result);
      return result;
    }
  }

  const payload: NotificationPayload = {
    id: generateNotificationId(),
    type: input.type,
    channel: input.channel,
    recipient: input.recipient,
    subject: input.subject,
    body: input.body,
    priority: input.priority ?? 'normal',
    metadata: input.metadata ?? {},
    createdAt: new Date(),
  };

  const adapter = this.adapters.get(payload.channel);
  if (!adapter) {
    this.logger.warn(
      `No adapter registered for channel "${payload.channel}". Notification ${payload.id} dropped.`,
    );
    const result: NotificationResult = {
      notificationId: payload.id,
      channel: payload.channel,
      success: false,
      error: `No adapter registered for channel: ${payload.channel}`,
      deliveredAt: new Date(),
    };
    this.results.push(result);
    this.historyService?.logNotification(input, result);
    return result;
  }

  const result = await adapter.send(payload);
  this.results.push(result);
  this.historyService?.logNotification(input, result);

  if (result.success) {
    this.logger.info(
      `Notification ${payload.id} delivered via ${payload.channel} to ${payload.recipient}`,
    );
  } else {
    this.logger.error(
      `Notification ${payload.id} failed via ${payload.channel}: ${result.error}`,
    );
  }

  return result;
}

