  describe('notification ordering', () => {
    it('should deliver notifications to the same recipient in order even when dispatched concurrently', async () => {
      const deliveryOrder: string[] = [];

      // Adapter where the first notification takes longer than the second
      const slowAdapter: NotificationAdapter = {
        channel: 'email' as NotificationChannel,
        async send(payload: NotificationPayload): Promise<NotificationResult> {
