          await new Promise((resolve) => setTimeout(resolve, delay));
          deliveryOrder.push(payload.subject ?? '');
          return {
            notificationId: payload.id,
            channel: payload.channel,
            success: true,
            deliveredAt: new Date(),
          };
        },
        async isAvailable() {
          return true;
        },
      };

